    evaluation = (U "\u76f8\u5173\u60278, \u65b0\u9896\u60277, \u5b8c\u6574\u5ea67. \u901a\u8fc7: visa policy change with direct travel-planning impact.")
    status = $statusGenerated
    publishStatus = $publishPending
    generatedImageUrl = ""
