$outPath = if ([System.IO.Path]::IsPathRooted($OutputJson)) { $OutputJson } else { Join-Path (Get-Location) $OutputJson }
$parent = Split-Path -Parent $outPath
if ($parent -and -not (Test-Path -LiteralPath $parent)) {
  New-Item -ItemType Directory -Path $parent | Out-Null
}
[System.IO.File]::WriteAllText($outPath, ($records | ConvertTo-Json -Depth 12), [System.Text.UTF8Encoding]::new($false))
Write-Host "Saved 6-category test batch to: $OutputJson"
